import { describe, it } from "vitest";
import assert from "node:assert/strict";
import { buildSplitPairs, parseUnifiedDiff } from "../../src/shared/git-diff/unified.ts";

const SAMPLE_DIFF = `diff --git a/src/a.ts b/src/a.ts
index 1111111..2222222 100644
--- a/src/a.ts
+++ b/src/a.ts
@@ -1,4 +1,5 @@ function sample()
 line one
-old two
+new two
 line three
+new four
@@ -20,2 +21,2 @@
-old twenty
+new twenty-one
diff --git a/docs/old.md b/docs/new.md
similarity index 88%
rename from docs/old.md
rename to docs/new.md
--- a/docs/old.md
+++ b/docs/new.md
@@ -1 +1 @@
-old title
+new title
`;

describe("parseUnifiedDiff", () => {
	it("parses multi-file unified diffs with hunks, paths, counts, and line numbers", () => {
		const result = parseUnifiedDiff(SAMPLE_DIFF);

		assert.equal(result.files.length, 2);
		assert.equal(result.isTruncated, false);

		const file = result.files[0];
		assert.equal(file.header, "diff --git a/src/a.ts b/src/a.ts");
		assert.equal(file.path, "src/a.ts");
		assert.equal(file.displayPath, "src/a.ts");
		assert.equal(file.status, "modified");
		assert.equal(file.additions, 3);
		assert.equal(file.deletions, 2);
		assert.equal(file.hunks.length, 2);
		assert.deepEqual(
			file.hunks[0].lines.map(line => [line.kind, line.oldLine, line.newLine, line.text]),
			[
				["context", 1, 1, "line one"],
				["remove", 2, null, "old two"],
				["add", null, 2, "new two"],
				["context", 3, 3, "line three"],
				["add", null, 4, "new four"],
			],
		);
		assert.equal(file.hunks[0].section, "function sample()");
		assert.equal(file.hunks[1].oldStart, 20);
		assert.equal(file.hunks[1].newStart, 21);
	});

	it("preserves rename metadata and display paths", () => {
		const file = parseUnifiedDiff(SAMPLE_DIFF).files[1];

		assert.equal(file.status, "renamed");
		assert.equal(file.oldPath, "docs/old.md");
		assert.equal(file.path, "docs/new.md");
		assert.equal(file.displayPath, "docs/old.md → docs/new.md");
		assert.equal(file.additions, 1);
		assert.equal(file.deletions, 1);
		assert.ok(file.meta.includes("rename from docs/old.md"));
		assert.ok(file.meta.includes("rename to docs/new.md"));
	});

	it("classifies new and deleted files from /dev/null headers", () => {
		const result = parseUnifiedDiff(`diff --git a/new.txt b/new.txt
new file mode 100644
index 0000000..1111111
--- /dev/null
+++ b/new.txt
@@ -0,0 +1,2 @@
+hello
+world
diff --git a/old.txt b/old.txt
deleted file mode 100644
index 2222222..0000000
--- a/old.txt
+++ /dev/null
@@ -1,2 +0,0 @@
-goodbye
-old world
`);

		assert.equal(result.files[0].status, "added");
		assert.equal(result.files[0].path, "new.txt");
		assert.equal(result.files[0].oldPath, undefined);
		assert.equal(result.files[0].additions, 2);
		assert.equal(result.files[0].deletions, 0);

		assert.equal(result.files[1].status, "deleted");
		assert.equal(result.files[1].path, "old.txt");
		assert.equal(result.files[1].deletions, 2);
		assert.equal(result.files[1].additions, 0);
	});

	it("captures binary metadata without requiring hunks", () => {
		const result = parseUnifiedDiff(`diff --git a/assets/logo.png b/assets/logo.png
new file mode 100644
index 0000000..1111111
Binary files /dev/null and b/assets/logo.png differ
`);
		const file = result.files[0];

		assert.equal(file.path, "assets/logo.png");
		assert.equal(file.status, "added");
		assert.equal(file.isBinary, true);
		assert.equal(file.hunks.length, 0);
		assert.ok(file.meta.includes("Binary files /dev/null and b/assets/logo.png differ"));
		assert.ok(result.warnings.some(warning => warning.includes("Binary diff detected")));
	});

	it("attaches no-newline markers to the preceding diff line", () => {
		const file = parseUnifiedDiff(`diff --git a/src/no-newline.ts b/src/no-newline.ts
index 1111111..2222222 100644
--- a/src/no-newline.ts
+++ b/src/no-newline.ts
@@ -1 +1 @@
-old
\\ No newline at end of file
+new
\\ No newline at end of file
`).files[0];

		assert.deepEqual(
			file.hunks[0].lines.map(line => [line.kind, line.text, line.noNewline === true]),
			[
				["remove", "old", true],
				["add", "new", true],
			],
		);
	});

	it("detects server truncation markers globally and on the current file", () => {
		const result = parseUnifiedDiff(`diff --git a/src/large.ts b/src/large.ts
index 1111111..2222222 100644
--- a/src/large.ts
+++ b/src/large.ts
@@ -1,2 +1,3 @@
 one
+two
${"--- Diff truncated (exceeded 500KB) ---"}
`);

		assert.equal(result.isTruncated, true);
		assert.equal(result.files[0].isTruncated, true);
		assert.ok(result.warnings.some(warning => warning.includes("truncated")));
	});

	it("creates a synthetic file for raw unified hunks without diff --git headers", () => {
		const result = parseUnifiedDiff(`--- a/plain.txt
+++ b/plain.txt
@@ -1 +1 @@
-old
+new
`);

		assert.equal(result.files.length, 1);
		assert.equal(result.files[0].path, "plain.txt");
		assert.equal(result.files[0].status, "modified");
		assert.equal(result.files[0].additions, 1);
		assert.equal(result.files[0].deletions, 1);
	});
});

describe("buildSplitPairs", () => {
	it("pairs delete/add runs and preserves context rows", () => {
		const lines = parseUnifiedDiff(`diff --git a/src/a.ts b/src/a.ts
index 1111111..2222222 100644
--- a/src/a.ts
+++ b/src/a.ts
@@ -1,5 +1,6 @@
 before
-old one
-old two
+new one
 context
+added only
-removed only
 after
`).files[0].hunks[0].lines;

		const pairs = buildSplitPairs(lines);

		assert.deepEqual(
			pairs.map(pair => [pair.left?.kind ?? null, pair.left?.text ?? null, pair.right?.kind ?? null, pair.right?.text ?? null]),
			[
				["context", "before", "context", "before"],
				["remove", "old one", "add", "new one"],
				["remove", "old two", null, null],
				["context", "context", "context", "context"],
				[null, null, "add", "added only"],
				["remove", "removed only", null, null],
				["context", "after", "context", "after"],
			],
		);
	});
});
